`,c(`// PID, uptime, mem, status`)]})},{tag:`B`,zh:{title:(0,t.jsx)(t.Fragment,{children:`fork vs cluster`}),desc:(0,t.jsx)(t.Fragment,{children:`fork = 单进程, cluster = 多进程 + Node 内置 round-robin。单机单核 / IO 重的 API 用 fork 就够, 算力密集才上 cluster。`})},en:{title:(0,t.jsx)(t.Fragment,{children:`fork vs cluster`}),desc:(0,t.jsx)(t.Fragment,{children:`fork = single process. cluster = N processes behind Node's round-robin balancer. IO-bound single-core APIs are fine on fork; CPU-bound services use cluster.`})},code:(0,t.jsxs)(`code`,{children:[`{`,`
